SELECT MAX(timestamp) AS latest_timestamp
FROM object_properties
WHERE device_object_id = 1;

SELECT u.user_name, u.email, u.role,
       (SELECT COUNT(*) FROM notifications n WHERE n.user_id = u.user_id) AS notification_count
FROM users u;

SELECT device_object_id, property_id, MAX(timestamp) AS last_updated
FROM object_properties
GROUP BY device_object_id, property_id;
